package com.spendwise.prototype.ui; import android.os.Bundle; import android.widget.*; import androidx.appcompat.app.AppCompatActivity; import androidx.lifecycle.lifecycleScope; import com.spendwise.prototype.R; import com.spendwise.prototype.data.AppDatabase; import com.spendwise.prototype.data.User; import kotlinx.coroutines.launch; class RegisterActivity:AppCompatActivity(){ override fun onCreate(b:Bundle?){ super.onCreate(b); setContentView(R.layout.activity_register); val db=AppDatabase.get(this); findViewById<Button>(R.id.btnCreate).setOnClickListener{ val u=findViewById<EditText>(R.id.etNewUser).text.toString(); val p=findViewById<EditText>(R.id.etNewPass).text.toString(); if(u.isBlank()||p.isBlank()){ Toast.makeText(this,"Fill all",Toast.LENGTH_SHORT).show(); return@setOnClickListener }; lifecycleScope.launch{ db.userDao().insert(User(username=u,password=p)); finish() } } } }